写出下面代码的输出结果：
int a=3, b=5, c=2;
if(a>b)
    if(b>c) printf("a>b>c");
    else printf("a>b且b<=c");
else
    if(b>c) printf("a<=b且b>c");
    else printf("a<=b且b<=c");

questions.answer:
#include <stdio.h>
int main() {
    int a, b, c, max;
    scanf("%d%d%d", &a, &b, &c);
    if(a>b)
        max = (a>c) ? a : c;
    else
        max = (b>c) ? b : c;
    printf("%d", max);
    return 0;
}

